INSERT INTO iscy_control_control (
    id, control_number, code, group_code, group_name, title, objective,
    evidence_guidance, owner_role, maturity_target, is_active, sort_order, created_at, updated_at
) VALUES
    (1, 1, 'ISCY-01', 'GRC', 'Governance & Risiko', 'Management-Verantwortung', 'Die oberste Leitung steuert Informationssicherheit, Cyberresilienz und Compliance nachvollziehbar.', 'Management-Freigaben, Rollen, Budgetentscheidungen, Sicherheitsziele und Verantwortlichkeitsmatrix.', 'Management', 4, TRUE, 10, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (2, 2, 'ISCY-02', 'GRC', 'Governance & Risiko', 'Risikomanagement', 'Risiken werden identifiziert, bewertet, behandelt und in Entscheidungen zur Steuerung genutzt.', 'Risikomethodik, Risikoregister, Treatment-Entscheidungen, Review-Protokolle und Risiko-KPIs.', 'Risk Owner', 4, TRUE, 20, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (3, 3, 'ISCY-03', 'GRC', 'Governance & Risiko', 'Projekt- und Demand-Governance', 'Neue Vorhaben, Demand und Architekturentscheidungen werden sicherheits- und complianceorientiert gesteuert.', 'Demand-Board, Security-Gates, Architekturentscheidungen, Datenschutz- und Sicherheitsfreigaben.', 'ISMS Manager', 3, TRUE, 30, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (4, 4, 'ISCY-04', 'GRC', 'Governance & Risiko', 'Incident Response', 'Sicherheitsvorfaelle werden erkannt, bewertet, eingedaemmt, gemeldet und nachbereitet.', 'Incident-Runbooks, Timeline, Meldepakete, Lessons Learned, Kommunikations- und Freigabenachweise.', 'CISO', 4, TRUE, 40, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (5, 5, 'ISCY-05', 'GRC', 'Governance & Risiko', 'Business Continuity Management', 'Kritische Leistungen bleiben auch bei Stoerungen beherrschbar und wiederanlaufbar.', 'BIA, Wiederanlaufplaene, Krisenorganisation, BCM-Tests und Abweichungsbehandlung.', 'Process Owner', 4, TRUE, 50, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (6, 6, 'ISCY-06', 'OPS', 'Betrieb & Daten', 'Backup und Restore', 'Backups sind vollstaendig, geschuetzt, getestet und an Wiederanlaufziele gekoppelt.', 'Backup-Konzept, Restore-Test, Retention, Offline-/Immutable-Kopie und Erfolgsprotokolle.', 'IT Operations', 4, TRUE, 60, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (7, 7, 'ISCY-07', 'OPS', 'Betrieb & Daten', 'Vulnerability Management', 'Schwachstellen werden risikobasiert priorisiert, behandelt und gegen Assets/Produkte nachvollzogen.', 'CVE-Bewertungen, Patch-Nachweise, Ausnahmen, KEV/EPSS-Kontext und Remediation-Status.', 'Security Operations', 4, TRUE, 70, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (8, 8, 'ISCY-08', 'OPS', 'Betrieb & Daten', 'Monitoring und Detection', 'Sicherheitsrelevante Ereignisse werden protokolliert, korreliert und handlungsfaehig alarmiert.', 'Logging-Konzept, SIEM-Regeln, Use Cases, Alarmtests, Retention und Detection-Nachweise.', 'Security Operations', 4, TRUE, 80, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (9, 9, 'ISCY-09', 'OPS', 'Betrieb & Daten', 'IAM und Access Control', 'Identitaeten, Rollen, Privilegien und Zugriffe werden lebenszyklusorientiert gesteuert.', 'MFA, Rollenmodell, Rezertifizierungen, privilegierte Konten, Joiner-Mover-Leaver-Nachweise.', 'Identity Owner', 4, TRUE, 90, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (10, 10, 'ISCY-10', 'OPS', 'Betrieb & Daten', 'Asset Management', 'Informationswerte, Systeme, Komponenten und Verantwortlichkeiten sind aktuell und klassifiziert.', 'Asset-Register, Kritikalitaet, Owner, CPE/PURL/SBOM-Bezug, Lifecycle und Scope-Entscheidungen.', 'Asset Owner', 4, TRUE, 100, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (11, 11, 'ISCY-11', 'OPS', 'Betrieb & Daten', 'Data Governance', 'Datenklassen, Schutzbedarf, Verarbeitung und Nachweise werden geregelt und kontrolliert.', 'Dateninventar, Klassifizierung, Aufbewahrung, Loeschung, Verschluesselung und DSGVO-Nachweise.', 'Data Owner', 4, TRUE, 110, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (12, 12, 'ISCY-12', 'PSC', 'Produkt & Lieferkette', 'Change Management', 'Aenderungen an Systemen, Produkten und Prozessen werden kontrolliert geplant, getestet und freigegeben.', 'Change-Tickets, Risikoabschaetzung, Freigaben, Rollback, Testnachweise und Notfall-Changes.', 'Change Manager', 3, TRUE, 120, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (13, 13, 'ISCY-13', 'PSC', 'Produkt & Lieferkette', 'Security by Design', 'Sicherheit, Datenschutz und Resilienz werden frueh in Anforderungen und Architektur verankert.', 'Security Requirements, Threat Modeling, Privacy by Design, Default-Konfiguration und Architekturreviews.', 'Product Security', 4, TRUE, 130, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (14, 14, 'ISCY-14', 'PSC', 'Produkt & Lieferkette', 'Secure SDLC', 'Software und Produkte werden ueber Entwicklung, Build, Test und Release abgesichert.', 'Code-Review, SAST/DAST, Dependency-Scanning, Release-Gates, Signaturen und Build-Nachweise.', 'Engineering', 4, TRUE, 140, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (15, 15, 'ISCY-15', 'PSC', 'Produkt & Lieferkette', 'Third-Party Risk', 'Dienstleister und Auslagerungen werden risikobasiert ausgewaehlt, vertraglich gesteuert und ueberwacht.', 'Lieferantenregister, Kritikalitaet, Vertragsklauseln, Auditrechte, SLA und Review-Nachweise.', 'Vendor Manager', 4, TRUE, 150, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (16, 16, 'ISCY-16', 'PSC', 'Produkt & Lieferkette', 'Supply Chain Transparency', 'Komponenten, Herkunft, Abhaengigkeiten und Advisories bleiben ueber den Lebenszyklus nachvollziehbar.', 'SBOM, CSAF, CPE/PURL, Komponentenregister, Supportfenster, Advisories und Lieferkettennachweise.', 'Product Security', 4, TRUE, 160, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (17, 17, 'ISCY-17', 'AUD', 'Menschen & Audits', 'Awareness und Training', 'Rollenbezogene Sicherheitskompetenz wird geplant, vermittelt und wirksam nachgewiesen.', 'Trainingsplan, Teilnahme, Phishing-Tests, Rollenmodule und Wirksamkeitsmessung.', 'HR / Awareness', 3, TRUE, 170, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (18, 18, 'ISCY-18', 'AUD', 'Menschen & Audits', 'Krisenkommunikation', 'Interne und externe Kommunikation in Vorfaellen und Krisen ist abgestimmt, freigegeben und geuebt.', 'Kontaktlisten, Kommunikationsmatrix, Freigaben, Vorlagen, Uebungen und Stakeholder-Protokolle.', 'Communications', 3, TRUE, 180, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (19, 19, 'ISCY-19', 'AUD', 'Menschen & Audits', 'Regulatorik-Management', 'Relevante Pflichten werden identifiziert, versioniert, gemappt und in Umsetzung ueberfuehrt.', 'Rechtsregister, Mapping-Versionen, Applicability, Gap-Analysen, Quellen und Aenderungsbewertung.', 'Compliance Manager', 4, TRUE, 190, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (20, 20, 'ISCY-20', 'AUD', 'Menschen & Audits', 'Policy-Management', 'Policies und Verfahren sind freigegeben, kommuniziert, versioniert und wirksam gepflegt.', 'Policy-Register, Freigaben, Versionshistorie, Kommunikation, Reviews und Ausnahmen.', 'ISMS Manager', 4, TRUE, 200, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (21, 21, 'ISCY-21', 'AUD', 'Menschen & Audits', 'Interne Audits', 'Interne Audits pruefen Umsetzung, Wirksamkeit und Nachweise gegen Scope und Risiken.', 'Auditprogramm, Stichproben, Feststellungen, Massnahmen, Wirksamkeitspruefung und Abschlussbericht.', 'Internal Audit', 3, TRUE, 210, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (22, 22, 'ISCY-22', 'AUD', 'Menschen & Audits', 'Externe Audits und Customer Assurance', 'Kunden-, Zertifizierungs- und Aufsichtsnachweise werden strukturiert vorbereitet und freigegeben.', 'Auditpakete, TISAX-/Kundennachweise, Freigaben, Scope, Findings und Kommunikationsprotokolle.', 'Compliance Manager', 3, TRUE, 220, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (23, 23, 'ISCY-23', 'LEARN', 'Lernen & Wandel', 'Management Review', 'Leitung und Governance-Gremien bewerten Status, Risiken, Wirksamkeit und Verbesserungen regelmaessig.', 'Management-Review-Protokolle, KPI, Risikoentwicklung, Auditstatus, Entscheidungen und Ressourcen.', 'Management', 4, TRUE, 230, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (24, 24, 'ISCY-24', 'LEARN', 'Lernen & Wandel', 'Verbesserung', 'Abweichungen, Lessons Learned und neue Risiken fuehren zu gesteuerter Verbesserung.', 'CAPA, Verbesserungsregister, Lessons Learned, Root Cause, Wirksamkeitspruefung und Roadmap-Bezug.', 'ISMS Manager', 4, TRUE, 240, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (25, 25, 'ISCY-25', 'LEARN', 'Lernen & Wandel', 'Tool-Governance', 'Sicherheits- und Compliance-Tools werden kontrolliert eingefuehrt, betrieben und abgeloest.', 'Tool-Inventar, Owner, Datenfluesse, Berechtigungen, Betriebskonzept, Exit und Review.', 'IT Operations', 3, TRUE, 250, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (26, 26, 'ISCY-26', 'LEARN', 'Lernen & Wandel', 'HR-Lifecycle Security', 'Eintritt, Wechsel, Austritt und Rollenwechsel sind mit Security- und Access-Prozessen gekoppelt.', 'Onboarding, Offboarding, Rollenwechsel, Schulungen, Zugriffsreviews und Nachweise zu kritischen Rollen.', 'HR / Identity', 4, TRUE, 260, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (27, 27, 'ISCY-27', 'LEARN', 'Lernen & Wandel', 'M&A-Governance', 'Akquisitionen, Carve-outs und Integrationen werden cyber-, daten- und complianceorientiert gesteuert.', 'Due-Diligence-Checklisten, Integrationsplan, Risikoentscheidungen, Datenuebergang und Lieferkettenbewertung.', 'Management', 3, TRUE, 270, '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z')
ON CONFLICT (id) DO NOTHING;

INSERT INTO iscy_control_regulatorymapping (
    id, control_id, framework, source_code, source_title, legal_reference, coverage_level, rationale, created_at, updated_at
) VALUES
    (1001, 1, 'NIS2', 'NIS2-20-21', 'Governance and cybersecurity risk management', 'NIS2 Art. 20, Art. 21', 'PRIMARY', 'Management-Verantwortung ist der Einstiegspunkt fuer Pflichten, Risikoentscheidungen und Nachweise.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1002, 1, 'DORA', 'DORA-5', 'Governance and organisation', 'DORA Art. 5', 'PRIMARY', 'DORA verankert ICT-Risikosteuerung beim Leitungsorgan.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1003, 1, 'ISO27001', 'ISO27001-5-6', 'Leadership and planning', 'ISO/IEC 27001 clauses 5 and 6', 'PRIMARY', 'Leadership, Ziele und Verantwortlichkeiten werden hier operativ gefuehrt.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1004, 2, 'NIS2', 'NIS2-21-2A', 'Risk analysis policies', 'NIS2 Art. 21(2)(a)', 'PRIMARY', 'Risikoanalyse ist eine Kernpflicht und wird ueber ISCY-02 gesteuert.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1005, 2, 'DORA', 'DORA-6-8', 'ICT risk management framework', 'DORA Art. 6 to 8', 'PRIMARY', 'DORA fordert ein ICT-Risikomanagement mit Identifikation und Schutz.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1006, 2, 'GDPR', 'GDPR-32', 'Risk appropriate security', 'GDPR Art. 32', 'SUPPORTING', 'Datenschutz-Sicherheit muss zum Risiko passend begruendet sein.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1007, 3, 'NIS2', 'NIS2-21-2D', 'Security in acquisition, development and maintenance', 'NIS2 Art. 21(2)(d)', 'SUPPORTING', 'Projekt- und Demand-Governance verankert Security-Anforderungen frueh.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1008, 3, 'CRA', 'CRA-13', 'Manufacturer lifecycle obligations', 'CRA Art. 13', 'SUPPORTING', 'Produktbezogene Anforderungen muessen im Demand- und Projektprozess landen.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1009, 3, 'AI_ACT', 'AI-ACT-17', 'Quality management system', 'AI Act Art. 17', 'SUPPORTING', 'AI-Governance benoetigt Freigaben, Rollen und lifecycle-nahe Steuerung.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1010, 4, 'NIS2', 'NIS2-23', 'Incident reporting obligations', 'NIS2 Art. 23', 'PRIMARY', 'ISCY-04 erzeugt Fallakte, Timeline und Meldepaket fuer NIS2.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1011, 4, 'DORA', 'DORA-17-23', 'ICT-related incident management and reporting', 'DORA Art. 17 to 23', 'PRIMARY', 'Incident Response ist zugleich DORA-Melde- und Klassifikationsanker.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1012, 4, 'GDPR', 'GDPR-33-34', 'Personal data breach notification', 'GDPR Art. 33 and 34', 'PRIMARY', 'Datenpannen werden als Incident-Sonderfall mit Kommunikations- und Freigabenachweisen behandelt.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1013, 4, 'TISAX', 'TISAX-INCIDENT', 'Incident and crisis handling', 'VDA ISA / TISAX assessment catalogue', 'SUPPORTING', 'TISAX-Pruefungen erwarten belastbare Reaktions- und Nachweisprozesse.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1014, 5, 'NIS2', 'NIS2-21-2C', 'Business continuity and crisis management', 'NIS2 Art. 21(2)(c)', 'PRIMARY', 'BCM, Backup und Krisenfaehigkeit werden als ein Steuerungsbereich betrachtet.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1015, 5, 'DORA', 'DORA-11', 'Response and recovery', 'DORA Art. 11', 'PRIMARY', 'DORA verlangt Wiederherstellungs- und Recovery-Faehigkeit.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1016, 5, 'ISO27001', 'ISO27001-A.5.30', 'ICT readiness for business continuity', 'ISO/IEC 27001 Annex A.5.30', 'PRIMARY', 'ISO-Readiness fuer Continuity wird hier zusammengefuehrt.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1017, 6, 'NIS2', 'NIS2-21-2C-BACKUP', 'Backup management', 'NIS2 Art. 21(2)(c)', 'PRIMARY', 'Backups und Restore-Tests sind konkrete Resilienz-Nachweise.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1018, 6, 'DORA', 'DORA-12', 'Backup policies and restoration methods', 'DORA Art. 12', 'PRIMARY', 'DORA operationalisiert Backup- und Wiederherstellungsanforderungen.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1019, 6, 'GDPR', 'GDPR-32-RESTORE', 'Restore availability and access', 'GDPR Art. 32(1)(c)', 'SUPPORTING', 'DSGVO verlangt zeitnahe Wiederherstellung personenbezogener Daten.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1020, 7, 'NIS2', 'NIS2-21-2D-F', 'Vulnerability handling and cyber hygiene', 'NIS2 Art. 21(2)(d), Art. 21(2)(f)', 'PRIMARY', 'CVE-Priorisierung und Remediation zahlen direkt auf NIS2 ein.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1021, 7, 'CRA', 'CRA-ANNEX-I-II', 'Vulnerability handling requirements', 'CRA Annex I Part II', 'PRIMARY', 'CRA-Schwachstellenannahme, Patches und Advisories werden hier gesteuert.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1022, 7, 'ISO27001', 'ISO27001-A.8.8', 'Management of technical vulnerabilities', 'ISO/IEC 27001 Annex A.8.8', 'PRIMARY', 'Technisches Schwachstellenmanagement ist der ISO-Anker fuer ISCY-07.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1023, 8, 'NIS2', 'NIS2-21-2B', 'Effectiveness and detection', 'NIS2 Art. 21(2)(b)', 'SUPPORTING', 'Monitoring liefert Nachweise fuer Wirksamkeit und Reaktion.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1024, 8, 'DORA', 'DORA-10', 'Detection', 'DORA Art. 10', 'PRIMARY', 'DORA fordert Erkennung anomaler Aktivitaeten und ICT-Vorfaelle.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1025, 8, 'AI_ACT', 'AI-ACT-12', 'Logging', 'AI Act Art. 12', 'SUPPORTING', 'AI-Systeme benoetigen Logs und Nachvollziehbarkeit.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1026, 9, 'NIS2', 'NIS2-21-2H-I', 'Access control and MFA', 'NIS2 Art. 21(2)(h), Art. 21(2)(i)', 'PRIMARY', 'IAM, MFA und Lifecycle sind direkte NIS2-Pflichten.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1027, 9, 'GDPR', 'GDPR-32-CONF', 'Confidentiality of processing systems', 'GDPR Art. 32(1)(b)', 'SUPPORTING', 'Zugriffskontrolle schuetzt Vertraulichkeit und Integritaet.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1028, 9, 'TISAX', 'TISAX-ACCESS', 'Identity and access management', 'VDA ISA / TISAX assessment catalogue', 'PRIMARY', 'TISAX bewertet Zugriffssteuerung und Privilegienmanagement.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1029, 10, 'NIS2', 'NIS2-21-2H-ASSET', 'Asset management', 'NIS2 Art. 21(2)(h)', 'PRIMARY', 'Asset-Transparenz ist Basis fuer Scope, Risiken und Meldebewertung.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1030, 10, 'DORA', 'DORA-8', 'Identification of ICT assets', 'DORA Art. 8', 'PRIMARY', 'DORA verlangt Identifikation von ICT-Assets und Abhaengigkeiten.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1031, 10, 'ISO27001', 'ISO27001-A.5.9', 'Inventory of information and associated assets', 'ISO/IEC 27001 Annex A.5.9', 'PRIMARY', 'ISO-Asset-Inventar wird in ISCY-10 operationalisiert.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1032, 11, 'GDPR', 'GDPR-5-30-32', 'Data principles, records and security', 'GDPR Art. 5, Art. 30, Art. 32', 'PRIMARY', 'Data Governance verbindet Verzeichnis, Schutzbedarf und technische Massnahmen.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1033, 11, 'AI_ACT', 'AI-ACT-10', 'Data and data governance', 'AI Act Art. 10', 'PRIMARY', 'AI-Data-Governance ist ein Sonderfall der Datensteuerung.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1034, 11, 'TISAX', 'TISAX-DATA-PROTECTION', 'Data protection objective', 'VDA ISA / TISAX assessment catalogue', 'SUPPORTING', 'TISAX umfasst Datenschutz- und Informationsschutzanforderungen.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1035, 12, 'NIS2', 'NIS2-21-2D-CHANGE', 'Security in maintenance', 'NIS2 Art. 21(2)(d)', 'PRIMARY', 'Aenderungen muessen sicherheitsbezogen bewertet und kontrolliert werden.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1036, 12, 'DORA', 'DORA-9-CHANGE', 'Change and ICT operations controls', 'DORA Art. 9', 'SUPPORTING', 'Change Management ist Teil belastbarer ICT-Betriebskontrollen.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1037, 12, 'CRA', 'CRA-13-CHANGE', 'Substantial modification and support period', 'CRA Art. 13', 'SUPPORTING', 'Produktveraenderungen brauchen Security-Gates und Rueckverfolgbarkeit.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1038, 13, 'CRA', 'CRA-ANNEX-I-I', 'Secure by design and default', 'CRA Annex I Part I', 'PRIMARY', 'Security by Design ist ein Hauptanker fuer CRA-Readiness.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1039, 13, 'GDPR', 'GDPR-25', 'Data protection by design and by default', 'GDPR Art. 25', 'PRIMARY', 'Privacy by Design wird in demselben Design-Gate nachgewiesen.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1040, 13, 'AI_ACT', 'AI-ACT-15', 'Accuracy, robustness and cybersecurity', 'AI Act Art. 15', 'SUPPORTING', 'AI-Cybersecurity wird als Designanforderung bewertet.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1041, 14, 'CRA', 'CRA-ANNEX-I-SDLC', 'Product security lifecycle', 'CRA Annex I', 'PRIMARY', 'Secure SDLC liefert Entwicklungs- und Release-Nachweise fuer CRA.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1042, 14, 'NIS2', 'NIS2-21-2D-SDLC', 'Secure development and maintenance', 'NIS2 Art. 21(2)(d)', 'PRIMARY', 'Sichere Entwicklung wird auch fuer NIS2-Umsetzung benoetigt.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1043, 14, 'ISO27001', 'ISO27001-A.8.25-A.8.29', 'Secure development lifecycle', 'ISO/IEC 27001 Annex A.8.25 to A.8.29', 'PRIMARY', 'ISO-Controls fuer sichere Entwicklung werden hier gebuendelt.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1044, 15, 'NIS2', 'NIS2-21-2C-SUPPLY', 'Supply chain security', 'NIS2 Art. 21(2)(c)', 'PRIMARY', 'Third-Party Risk operationalisiert Lieferkettenpflichten.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
