    (1054, 18, 'DORA', 'DORA-19-20-COMMS', 'Incident reporting content and templates', 'DORA Art. 19 and 20', 'SUPPORTING', 'DORA-Meldungen benoetigen strukturierte Kommunikation und Templates.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
