    (1070, 23, 'NIS2', 'NIS2-20-REVIEW', 'Management accountability', 'NIS2 Art. 20', 'PRIMARY', 'Leitungsorgane koennen den Status ueber ISCY-23 nachvollziehen.', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
