    (1, 8, 'PARTIAL', 3, 'PARTIAL', 1, 'Agent-Posture und Detection-Kontext vorhanden, SIEM-Use-Cases ausbauen.', '2026-06-14', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1, 9, 'PARTIAL', 3, 'PARTIAL', 1, 'RBAC vorhanden, formale Access-Reviews noch vertiefen.', '2026-06-14', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1, 10, 'IMPLEMENTED', 4, 'EVIDENCED', 1, 'Asset-Register inklusive CPE/PURL/SBOM-Feldern ist verfuegbar.', '2026-06-14', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
