    (1, 14, 'IMPLEMENTED', 4, 'EVIDENCED', 1, 'Secure-SDLC-Fragen und Product-Security-Roadmap sind angebunden.', '2026-06-14', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1, 15, 'PARTIAL', 3, 'PARTIAL', 1, 'Lieferantenbasis vorhanden, DORA-Registertiefe noch ausbauen.', '2026-06-14', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1, 16, 'PARTIAL', 3, 'PARTIAL', 1, 'SBOM/CSAF-Metadaten existieren, Importvalidierung ist naechster Schritt.', '2026-06-14', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1, 17, 'PARTIAL', 3, 'PARTIAL', 1, 'Awareness-Fragen vorhanden, Trainingsworkflow noch schlanker machen.', '2026-06-14', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1, 18, 'GAP', 1, 'MISSING', 1, 'Krisenkommunikation sollte als eigener Runbook-/Template-Typ folgen.', '2026-06-14', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1, 19, 'PARTIAL', 3, 'PARTIAL', 1, 'Requirements und Mapping-Versionen sind da, DORA/DSGVO/TISAX-Mappings werden erweitert.', '2026-06-14', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1, 20, 'PARTIAL', 3, 'PARTIAL', 1, 'Policies sind nachweisbar, Policy-CRUD und Freigabeworkflow fehlen noch.', '2026-06-14', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1, 21, 'PARTIAL', 2, 'PARTIAL', 1, 'Audit-/Report-Grundlage existiert, Auditprogramm fehlt als eigener Workflow.', '2026-06-14', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1, 22, 'GAP', 1, 'MISSING', 1, 'Customer-Assurance-Paket und TISAX-Export noch offen.', '2026-06-14', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1, 23, 'PARTIAL', 2, 'PARTIAL', 1, 'Management-Review sollte aus Dashboard, Risiken, Audits und Roadmap generiert werden.', '2026-06-14', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1, 24, 'PARTIAL', 3, 'PARTIAL', 1, 'Roadmap und Measures vorhanden, CAPA-Wirksamkeitspruefung noch ausbauen.', '2026-06-14', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1, 25, 'GAP', 1, 'MISSING', 1, 'Tool-Governance-Register fehlt noch.', '2026-06-14', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1, 26, 'PARTIAL', 2, 'PARTIAL', 1, 'HR-Lifecycle ist ueber IAM-Fragen angedeutet, eigener Workflow fehlt.', '2026-06-14', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z'),
    (1, 27, 'GAP', 0, 'MISSING', 1, 'M&A-Governance ist als neues Fachmodul noch offen.', '2026-06-14', '2026-06-14T00:00:00Z', '2026-06-14T00:00:00Z')
